import{_ as a,o as r,c as o,a2 as n}from"./chunks/framework.BQ1gajhD.js";const u=JSON.parse('{"title":"绮望楼","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/jingshan/qiwang-lou.md","filePath":"landmarks/jingshan/qiwang-lou.md","lastUpdated":1784720050000}'),e={name:"landmarks/jingshan/qiwang-lou.md"};function s(l,t,i,d,h,p){return r(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="绮望楼" tabindex="-1">绮望楼 <a class="header-anchor" href="#绮望楼" aria-label="Permalink to &quot;绮望楼&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1630925638589-c82f036d962d?w=1200&amp;q=80" alt="绮望楼"></p><blockquote><p>&quot;昔日八旗官学地，今朝游客歇脚处。红墙绿瓦间，藏着景山从皇家禁苑到人民公园的百年变迁。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>绮望楼位于景山公园东门内，是清代官式建筑的代表之一。这座建筑原为清代八旗子弟的官学所在，是专门为满族贵族子弟设立的教育机构，培养了大量清代中后期的文武人才。如今，绮望楼作为景山公园管理处和游客服务中心使用，虽然建筑内部不对外开放，但其外观依然保留了清代官式建筑的典型风貌，是研究清代教育制度和建筑艺术的重要实物资料。</p><p>绮望楼的建筑规制严谨，红墙绿瓦，雕梁画栋，门前的一对石狮子和台阶上的龙纹雕刻，都彰显着昔日皇家教育机构的不凡身份。对于建筑爱好者和历史研究者来说，即使只能外观，绮望楼依然是一处不可多得的观摩对象。</p><hr><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><h3 id="建筑形制" tabindex="-1">建筑形制 <a class="header-anchor" href="#建筑形制" aria-label="Permalink to &quot;建筑形制&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项目</th><th>详情</th></tr></thead><tbody><tr><td><strong>建筑类型</strong></td><td>清代官式建筑</td></tr><tr><td><strong>屋顶形制</strong></td><td>绿琉璃瓦硬山顶</td></tr><tr><td><strong>建筑色彩</strong></td><td>红墙绿瓦，彩绘斗拱</td></tr><tr><td><strong>装饰特色</strong></td><td>门前石狮、龙纹台阶、匾额书法</td></tr><tr><td><strong>历史功能</strong></td><td>清代八旗官学</td></tr><tr><td><strong>现状</strong></td><td>景山公园管理处、游客服务中心</td></tr></tbody></table><p>绮望楼的建筑布局遵循了清代官式建筑的严格规制。建筑主体坐北朝南，面阔五间，进深三间，整体呈长方形布局。屋顶采用绿琉璃瓦硬山顶，与景山五方亭中的副亭色彩相呼应。檐下的斗拱和梁枋上，保存有较为完好的清代彩画，题材以龙凤、花卉、云纹为主，虽然历经数百年，部分色彩已经褪去，但依然可以想见当年的华丽。</p><p>门前的石狮子造型生动，一雄一雌，是清代石雕艺术的典型作品。台阶上的龙纹雕刻虽然因长期磨损而有所模糊，但龙的基本轮廓依然清晰可辨。这些细节，无不透露着一个时代对等级制度的严格维护和对美的追求。</p><h3 id="门前景观" tabindex="-1">门前景观 <a class="header-anchor" href="#门前景观" aria-label="Permalink to &quot;门前景观&quot;">​</a></h3><p>绮望楼前是一片开阔的广场，种植有数株百年以上的古柏，树干粗壮，枝繁叶茂。这些古树与红墙绿瓦的建筑相映成趣，营造出一种古朴宁静的氛围。广场上还设有石凳，是游人休息、纳凉的好去处。</p><hr><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="八旗官学的兴衰" tabindex="-1">八旗官学的兴衰 <a class="header-anchor" href="#八旗官学的兴衰" aria-label="Permalink to &quot;八旗官学的兴衰&quot;">​</a></h3><p>绮望楼作为八旗官学的历史，可以追溯到清代康熙年间。八旗制度是清代满族社会的基本组织形式，八旗子弟自幼接受骑射训练，同时也需要学习汉文化。为了培养八旗子弟的文化素养，清廷在景山设立了这处官学，聘请名师授课，教授四书五经、诗词文章等科目。</p><p>在清代中后期，绮望楼官学培养出了不少著名人物，包括一些在朝堂上举足轻重的文臣武将。然而，随着清朝国力的衰退和新式教育的兴起，传统的八旗官学逐渐走向没落。清末新政期间，许多官学被改组为新式学堂，绮望楼的办学功能也随之终结。</p><h3 id="从皇家禁苑到人民公园" tabindex="-1">从皇家禁苑到人民公园 <a class="header-anchor" href="#从皇家禁苑到人民公园" aria-label="Permalink to &quot;从皇家禁苑到人民公园&quot;">​</a></h3><p>景山的历史，是一部从皇家禁苑到人民公园的变迁史。</p><p><strong>金代</strong>：这里曾是金中都的&quot;瑶屿行宫&quot;，是皇家游幸的场所。</p><p><strong>元代</strong>：成为元大都的中心，称&quot;青山&quot;，是皇家园林的雏形。</p><p><strong>明代</strong>：永乐年间修建紫禁城时，将拆除元故宫的渣土堆积于此，形成&quot;万岁山&quot;，又称&quot;镇山&quot;&quot;堆煤山&quot;。明代在山上种植了大量果树，并修建了亭台楼阁，成为皇家的后花园。</p><p><strong>清代</strong>：顺治年间改名为&quot;景山&quot;，取&quot;仰瞻高山，景行行止&quot;之意。清代对景山进行了大规模的修缮和扩建，形成了万春亭、五方亭、绮望楼等建筑群，并修建了寿皇殿、观德殿等祭祀建筑。</p><p><strong>民国</strong>：1928年，景山正式开放为公园，成为北京市民休闲娱乐的公共场所。</p><p><strong>现代</strong>：现为全国重点文物保护单位，国家AAAA级旅游景区，每年吸引数百万游客前来参观。</p><hr><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><p><strong>清代官式建筑外观</strong>：绮望楼虽然不是最高等级的皇家建筑，但其严谨的布局、精美的彩画和雕刻，依然代表了清代官式建筑的高超水准。建筑爱好者可以仔细观察其屋顶、斗拱、门窗等细节。</p></li><li><p><strong>门前石狮与龙纹台阶</strong>：门前的石狮子造型威猛，是清代石雕艺术的精品。台阶上的龙纹雕刻虽然有所磨损，但龙的形态依然清晰可辨，值得驻足细观。</p></li><li><p><strong>古树名木</strong>：绮望楼前的古柏树龄均在百年以上，是景山古树名木的重要组成部分。其中一棵被称为&quot;遮荫侯&quot;的白皮松，相传为清代所植，树干挺拔，树皮斑驳，极具观赏价值。</p></li><li><p><strong>景山公园管理处</strong>：绮望楼内现设有游客服务中心，提供咨询、导览、急救等服务。游客可以在此获取景山公园的导览图和相关信息。</p></li></ol><hr><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li><strong>外观为主</strong>：绮望楼内部不对外开放，参观以外观为主，建议在楼前的广场上驻足欣赏。</li><li><strong>最佳时间</strong>：清晨或傍晚光线柔和，最适合拍摄建筑外观和门前古树。</li><li><strong>结合游览</strong>：绮望楼靠近景山东门，建议与东门附近的其他景点（如观德殿遗址）一起游览。</li><li><strong>了解背景</strong>：建议参观前了解清代八旗制度和官学教育的相关知识，可以更好地理解绮望楼的历史价值。</li><li><strong>注意安静</strong>：绮望楼现为办公场所，参观时请保持安静，不要影响办公秩序。</li></ul><hr><p><strong>📍 位置</strong>：景山公园东门内，从东门入园即可看到</p><p><strong>⏱️ 建议游览</strong>：15-20分钟</p><p><strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/jingshan/">景山公园概览</a></p>',37)])])}const q=a(e,[["render",s]]);export{u as __pageData,q as default};
